Span<nint> integers = stackalloc nint[] { 1, 2, 3, 4, 5 };

Console.WriteLine($"Length: {integers.Length}");
Console.WriteLine($"Element size: {sizeof(nint)} bytes");

nint sum = 0;
for (int i = 0; i < integers.Length; i++)
{
    sum += integers[i];
    Console.WriteLine($"  [{i}] = {integers[i]}");
}
Console.WriteLine($"Sum: {sum}");

